  `id_centro_custo` int(11) DEFAULT NULL,
  `fornecedor` varchar(255) DEFAULT 'Nenhum',
  `status` enum('Ativa','Expirada','Cancelada') DEFAULT 'Ativa',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id_licenca`)
